function solve(nums) {
    const n = nums.length;

    // 1. Find the peak index
    let peakIndex = 0;
    // The array is guaranteed to be unimodal (strictly increasing then strictly decreasing).
    // We can find the peak by checking where nums[i] > nums[i+1] for the first time.
    for (let i = 0; i < n - 1; i++) {
        if (nums[i] < nums[i + 1]) {
            // Still increasing
        } else {
            // nums[i] >= nums[i+1]. Since it's strictly increasing then strictly decreasing,
            // the peak must be at index i.
            peakIndex = i;
            break;
        }
    }

    // Handle the case where the array is strictly increasing (e.g., [1, 2, 3]).
    // In this case, the peak is the last element (index n-1).
    if (peakIndex === 0 && nums[n - 2] > nums[n - 1]) {
         // This case should not happen for a proper unimodal array where the peak is found.
         // If the loop finishes without breaking, the peak is the last element.
    } else if (peakIndex === 0 && nums[0] < nums[1]) {
        // If the loop finished and peakIndex is still 0, it means it was always increasing,
        // so the peak is the last element.
        if (nums[n - 2] < nums[n - 1]) {
            peakIndex = n - 1;
        }
    } else if (peakIndex === 0 && n === 1) {
        // Trivial case, though constraints say n >= 3.
        peakIndex = 0;
    }

    // Re-run peak finding more robustly since the simple loop logic above might fail
    // for purely increasing/decreasing sequences, though the problem guarantees a peak.
    // Since n >= 3, the peak is definitely not at index 0 or n-1 unless it's monotonic.
    // A unimodal sequence must have a change in slope unless it's fully monotonic.

    let foundPeak = false;
    for (let i = 0; i < n - 1; i++) {
        if (nums[i] < nums[i + 1] && nums[i + 1] > nums[i + 2]) {
            peakIndex = i + 1;
            foundPeak = true;
            break;
        } else if (i === n - 2 && nums[i] < nums[i + 1]) {
            // Case: Strictly increasing array like [1, 2, 3] -> Peak at n-1
            peakIndex = n - 1;
            foundPeak = true;
            break;
        }
    }

    // If still not found, it must be strictly decreasing like [3, 2, 1] -> Peak at 0
    if (!foundPeak) {
        if (nums[0] > nums[1]) {
            peakIndex = 0;
        } else {
            // Must be strictly increasing, peak is at n-1
            peakIndex = n - 1;
        }
    }

    // Given the problem constraints (unimodal), the peak finding logic is simplified:
    // Iterate until nums[i] > nums[i+1] or we reach the end. The peak is the index right before the drop.
    peakIndex = 0;
    while (peakIndex < n - 1 && nums[peakIndex] < nums[peakIndex + 1]) {
        peakIndex++;
    }


    // 2. Calculate sums
    let sumIncreasing = 0;
    // Increasing part: from index 0 to peakIndex (inclusive)
    for (let i = 0; i <= peakIndex; i++) {
        sumIncreasing += nums[i];
    }

    let sumDecreasing = 0;
    // Decreasing part: from peakIndex to index n - 1 (inclusive)
    for (let i = peakIndex; i < n; i++) {
        sumDecreasing += nums[i];
    }

    // 3. Compare sums and return result
    if (sumIncreasing > sumDecreasing) {
        return 0;
    } else if (sumDecreasing > sumIncreasing) {
        return 1;
